import React from 'react';
import { Button } from '../common/Button';
import { NotificationBell } from '../notifications/NotificationBell';
import { UserMenu } from './UserMenu';
import { Moon, Sun, ChevronRight, ChevronLeft, ScanEye } from 'lucide-react';
import { useInspector } from '../../context/InspectorContext';
import { useTheme } from '../../context/ThemeContext';
import { Inspectable } from '../common/Inspectable';

interface HeaderProps {
  title?: string;
  onToggleSidebar?: () => void;
  isSidebarCollapsed?: boolean;
}

export function Header({ title, onToggleSidebar, isSidebarCollapsed }: HeaderProps) {
  const { isInspecting, toggleInspector } = useInspector();
  const { theme, toggleTheme } = useTheme();

  return (
    <Inspectable name="Header">
    <header className="h-16 bg-theme-surface border-b border-theme-border flex items-center justify-between px-6">
      {/* Left side */}
      <div className="flex items-center gap-4">
        {/* Sidebar toggle */}
        {onToggleSidebar && (
          <Button variant="ghost" size="sm" onClick={onToggleSidebar} className="p-2">
            {isSidebarCollapsed ? (
              <ChevronRight className="w-5 h-5 text-theme-muted" />
            ) : (
              <ChevronLeft className="w-5 h-5 text-theme-muted" />
            )}
          </Button>
        )}
        {/* Title */}
        {title && <h1 className="text-xl font-semibold text-theme-text">{title}</h1>}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-4">
        {/* Inspector toggle */}
        <Button variant="ghost" size="sm" onClick={toggleInspector} className="p-2">
          <ScanEye className={`w-5 h-5 ${isInspecting ? 'text-brand-primary' : 'text-theme-muted'}`} />
        </Button>

        {/* Theme toggle */}
        <Button variant="ghost" size="sm" onClick={toggleTheme} className="p-2">
          {theme === 'dark' ? (
            <Sun className="w-5 h-5 text-theme-muted" />
          ) : (
            <Moon className="w-5 h-5 text-theme-muted" />
          )}
        </Button>

        {/* Notifications */}
        <NotificationBell />

        {/* User menu */}
        <div className="pl-4 border-l border-theme-border">
          <UserMenu />
        </div>
      </div>
    </header>
    </Inspectable>
  );
}

