import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useProjects } from '../hooks/useProjects';
import { useActivePlans } from '../hooks/useOrchestration';
import { useJobs, useJobStats } from '../hooks/useJobs';
import { useUnreadCount } from '../hooks/useNotifications';
import { useDashboardActivity, useLastWeekActivity } from '../hooks/useActivity';
import { Card, CardHeader, CardTitle } from '../components/common/Card';
import { Button } from '../components/common/Button';
import { ProjectGrid } from '../components/projects/ProjectGrid';
import { NewProjectModal } from '../components/projects/NewProjectModal';
import { PlanCard } from '../components/orchestration/PlanCard';
import { BeadQuickView } from '../components/beads/BeadQuickView';
import { JobTerminal } from '../components/jobs/JobTerminal';
import { formatTimeAgo } from '../components/activity/activity-utils';
import { TimelineSection } from '../components/activity/TimelineSection';
import { ActivityCluster } from '../components/activity/ActivityCluster';
import { groupActivitiesForTimeline, groupByActor } from '../utils/activity-grouping';
import {
  FolderPlus,
  Activity,
  CheckCircle2,
  Cpu,
  Play,
  Clock,
  Bell,
  Rocket,
  Github,
  Layers,
  ChevronRight,
  Loader2,
  RefreshCw,
} from 'lucide-react';
import { clsx } from 'clsx';

export function Dashboard() {
  const navigate = useNavigate();
  const { data: projects, isLoading } = useProjects();
  const activePlans = useActivePlans();
  const { data: jobStats } = useJobStats();
  const { data: jobs = [] } = useJobs();
  const { data: unreadCount } = useUnreadCount();
  const { data: thisWeekEntries, isLoading: activityLoading, refetch: refetchActivity, isFetching: activityFetching } = useDashboardActivity();
  const [lastWeekExpanded, setLastWeekExpanded] = React.useState(false);
  const { data: lastWeekEntries, isLoading: lastWeekLoading } = useLastWeekActivity(lastWeekExpanded);
  const [showNewProject, setShowNewProject] = React.useState(false);
  const [selectedBeadId, setSelectedBeadId] = React.useState<{ id: string; projectId: string } | null>(null);
  const [selectedJobId, setSelectedJobId] = React.useState<string | null>(null);

  // Memoize grouping so it doesn't recompute on every render
  const thisWeekSections = React.useMemo(
    () => thisWeekEntries ? groupActivitiesForTimeline(thisWeekEntries) : [],
    [thisWeekEntries]
  );
  const lastWeekClusters = React.useMemo(
    () => lastWeekEntries ? groupByActor(lastWeekEntries) : [],
    [lastWeekEntries]
  );

  const activeJobs = jobs.filter(
    (j) => j.status === 'running' || j.status === 'queued'
  );

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <StatCard
          title="Projects"
          value={projects?.length || 0}
          icon={<FolderPlus className="w-5 h-5" />}
          color="primary"
        />
        <StatCard
          title="Agents Running"
          value={jobStats?.running || 0}
          icon={<Play className="w-5 h-5" />}
          color="secondary"
        />
        <StatCard
          title="Queued"
          value={jobStats?.queued || 0}
          icon={<Clock className="w-5 h-5" />}
          color="warning"
        />
        <StatCard
          title="Completed"
          value={jobStats?.completed || 0}
          icon={<CheckCircle2 className="w-5 h-5" />}
          color="accent"
        />
        <StatCard
          title="Alerts"
          value={unreadCount || 0}
          icon={<Bell className="w-5 h-5" />}
          color="danger"
        />
      </div>

      {/* Projects Section */}
      <Card>
        <CardHeader>
          <CardTitle>Your Projects</CardTitle>
          <Button
            size="sm"
            leftIcon={<FolderPlus className="w-4 h-4" />}
            onClick={() => setShowNewProject(true)}
          >
            New Project
          </Button>
        </CardHeader>

        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <div className="animate-spin w-8 h-8 border-2 border-brand-primary border-t-transparent rounded-full" />
          </div>
        ) : projects && projects.length > 0 ? (
          <ProjectGrid projects={projects} />
        ) : (
          <EmptyState onCreateProject={() => setShowNewProject(true)} />
        )}
      </Card>

      {/* Active Plans */}
      {activePlans.length > 0 && (
        <Card>
          <CardHeader>
            <div className="flex items-center gap-2">
              <Layers className="w-5 h-5 text-brand-primary" />
              <CardTitle>Active Plans</CardTitle>
            </div>
            <Link
              to="/orchestration"
              className="text-sm text-brand-primary hover:text-brand-primary/80 flex items-center gap-1"
            >
              View all
              <ChevronRight className="w-4 h-4" />
            </Link>
          </CardHeader>
          <div className="grid gap-4 md:grid-cols-2">
            {activePlans.slice(0, 2).map(plan => (
              <PlanCard
                key={plan.id}
                plan={plan}
                onClick={() => navigate('/orchestration')}
                onDelete={() => {}}
              />
            ))}
          </div>
        </Card>
      )}

      {/* Job Queue */}
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Cpu className="w-5 h-5 text-brand-primary" />
            <CardTitle>Job Queue</CardTitle>
          </div>
          <Link
            to="/jobs"
            className="text-sm text-brand-primary hover:text-brand-primary/80 flex items-center gap-1"
          >
            View all
            <ChevronRight className="w-4 h-4" />
          </Link>
        </CardHeader>

        {/* Worker Capacity Bar */}
        {jobStats?.concurrency && (
          <div className="flex items-center justify-between px-6 pb-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-lg bg-brand-accent/10 flex items-center justify-center">
                <Cpu className="w-5 h-5 text-brand-accent" />
              </div>
              <div>
                <p className="text-sm font-medium text-theme-text">Worker Capacity</p>
                <p className="text-xs text-theme-muted">
                  {jobStats.concurrency.running} of {jobStats.concurrency.max} workers active
                </p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <div className="w-48 h-2 bg-theme-border rounded-full overflow-hidden">
                <div
                  className="h-full bg-brand-primary transition-all"
                  style={{
                    width: `${(jobStats.concurrency.running / jobStats.concurrency.max) * 100}%`,
                  }}
                />
              </div>
              <span className="text-sm text-theme-muted">
                {jobStats.concurrency.available} available
              </span>
            </div>
          </div>
        )}

        {/* Active Jobs List */}
        {activeJobs.length > 0 ? (
          <div className="divide-y divide-theme-border/50">
            {activeJobs.slice(0, 5).map((job) => (
              <Link
                key={job.id}
                to="/jobs"
                className="flex items-center gap-3 px-6 py-3 hover:bg-theme-border/30 transition-colors"
              >
                <span
                  className={clsx(
                    'w-2.5 h-2.5 rounded-full flex-shrink-0',
                    job.status === 'running'
                      ? 'bg-brand-primary animate-pulse'
                      : 'bg-yellow-500'
                  )}
                />
                <p className="text-sm text-theme-text truncate flex-1">
                  {job.prompt}
                </p>
                <span className="text-xs text-theme-muted flex-shrink-0">
                  {formatTimeAgo(job.created_at)}
                </span>
              </Link>
            ))}
          </div>
        ) : (
          <div className="text-center py-6 text-theme-muted">
            <Activity className="w-6 h-6 mx-auto mb-1 opacity-50" />
            <p className="text-sm">No active jobs</p>
          </div>
        )}
      </Card>

      {/* Recent Activity */}
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Activity className="w-5 h-5 text-brand-primary" />
            <CardTitle>Recent Activity</CardTitle>
          </div>
          <button
            onClick={() => refetchActivity()}
            disabled={activityFetching}
            className="text-sm text-theme-muted hover:text-theme-text transition-colors disabled:opacity-50"
            title="Refresh activity"
          >
            <RefreshCw className={clsx('w-4 h-4', activityFetching && 'animate-spin')} />
          </button>
        </CardHeader>

        {activityLoading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="w-5 h-5 animate-spin text-theme-muted" />
          </div>
        ) : thisWeekSections.length > 0 ? (
          <div className="py-2">
            {thisWeekSections.map((section) => (
              <TimelineSection key={section.label} label={section.label}>
                {section.activities.map((cluster, i) => (
                  <ActivityCluster
                    key={i}
                    cluster={cluster}
                    onBeadClick={(id, projectId) => setSelectedBeadId({ id, projectId })}
                    onJobClick={(id) => setSelectedJobId(id)}
                  />
                ))}
              </TimelineSection>
            ))}

            {/* Last Week — lazy loaded on expand */}
            <TimelineSection
              label="Last Week"
              defaultCollapsed
              onExpand={() => setLastWeekExpanded(true)}
              loading={lastWeekLoading}
              empty={lastWeekExpanded && !lastWeekLoading && lastWeekClusters.length === 0}
            >
              {lastWeekClusters.map((cluster, i) => (
                <ActivityCluster
                  key={i}
                  cluster={cluster}
                  onBeadClick={(id, projectId) => setSelectedBeadId({ id, projectId })}
                  onJobClick={(id) => setSelectedJobId(id)}
                />
              ))}
            </TimelineSection>
          </div>
        ) : (
          <div className="text-center py-6 text-theme-muted">
            <Activity className="w-6 h-6 mx-auto mb-1 opacity-50" />
            <p className="text-sm">No recent activity</p>
          </div>
        )}
      </Card>

      {/* New Project Modal */}
      <NewProjectModal
        isOpen={showNewProject}
        onClose={() => setShowNewProject(false)}
      />

      {/* Activity Bead Detail Modal */}
      {selectedBeadId && (
        <BeadQuickView
          beadId={selectedBeadId.id}
          projectId={selectedBeadId.projectId}
          isOpen={!!selectedBeadId}
          onClose={() => setSelectedBeadId(null)}
        />
      )}

      {/* Activity Job Terminal Modal */}
      {selectedJobId && (
        <JobTerminal
          jobId={selectedJobId}
          isModal
          onClose={() => setSelectedJobId(null)}
        />
      )}
    </div>
  );
}

function StatCard({
  title,
  value,
  icon,
  color,
}: {
  title: string;
  value: number;
  icon: React.ReactNode;
  color: 'primary' | 'secondary' | 'accent' | 'warning' | 'danger';
}) {
  const colors = {
    primary: 'text-brand-primary bg-brand-primary/10',
    secondary: 'text-brand-secondary bg-brand-secondary/10',
    accent: 'text-brand-accent bg-brand-accent/10',
    warning: 'text-yellow-500 bg-yellow-500/10',
    danger: 'text-brand-danger bg-brand-danger/10',
  };

  return (
    <Card className="flex items-center gap-4">
      <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${colors[color]}`}>
        {icon}
      </div>
      <div>
        <p className="text-2xl font-bold text-theme-text">{value}</p>
        <p className="text-sm text-theme-muted">{title}</p>
      </div>
    </Card>
  );
}

function EmptyState({ onCreateProject }: { onCreateProject: () => void }) {
  const navigate = useNavigate();

  return (
    <div className="text-center py-12">
      <div className="w-16 h-16 bg-brand-primary/10 border border-brand-primary/30 rounded-2xl flex items-center justify-center mx-auto mb-5">
        <Rocket className="w-8 h-8 text-brand-primary" />
      </div>
      <h3 className="text-lg font-medium text-theme-text mb-2">Welcome to Dev Dash</h3>
      <p className="text-theme-muted mb-6 max-w-sm mx-auto">
        Connect a repo, dispatch AI agents, and manage tasks — all from one dashboard.
      </p>
      <div className="flex flex-wrap justify-center gap-6 mb-8 text-sm text-theme-muted">
        <div className="flex items-center gap-1.5">
          <Cpu className="w-4 h-4 text-brand-primary" />
          AI Agents
        </div>
        <div className="flex items-center gap-1.5">
          <Activity className="w-4 h-4 text-brand-secondary" />
          Task Board
        </div>
        <div className="flex items-center gap-1.5">
          <Github className="w-4 h-4 text-brand-accent" />
          Git Integration
        </div>
      </div>
      <div className="flex justify-center gap-3">
        <Button
          variant="secondary"
          onClick={() => navigate('/onboarding')}
          leftIcon={<Github className="w-4 h-4" />}
        >
          Import from GitHub
        </Button>
        <Button onClick={onCreateProject} leftIcon={<FolderPlus className="w-4 h-4" />}>
          Create Project
        </Button>
      </div>
    </div>
  );
}

