import { useQuery, useInfiniteQuery, useMutation, useQueryClient, keepPreviousData } from '@tanstack/react-query';
import { useMemo, useEffect } from 'react';
import { api } from '../services/api';
import type { Bead, BeadStatus, JobResult, PaginatedResponse } from '../types';

export function useBeads(projectId: string, filters?: {
  status?: string;
  type?: string;
  priority?: string;
  search?: string;
}) {
  const query = useInfiniteQuery({
    queryKey: ['beads', projectId, filters],
    queryFn: async ({ pageParam }: { pageParam: string | undefined }) => {
      const params = new URLSearchParams({ projectId, limit: '200' });
      if (filters?.status) params.set('status', filters.status);
      if (filters?.type) params.set('type', filters.type);
      if (filters?.priority) params.set('priority', filters.priority);
      if (filters?.search) params.set('search', filters.search);
      if (pageParam) params.set('cursor', pageParam);

      const response = await api.get<PaginatedResponse<Bead>>(`/beads?${params.toString()}`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    initialPageParam: undefined as string | undefined,
    getNextPageParam: (lastPage) =>
      lastPage.hasMore ? (lastPage.nextCursor ?? undefined) : undefined,
    enabled: !!projectId,
    staleTime: 10_000,
    placeholderData: keepPreviousData,
    refetchInterval: 30000, // Fallback poll every 30s (SSE handles real-time)
  });

  // Auto-fetch remaining pages in the background
  useEffect(() => {
    if (query.hasNextPage && !query.isFetchingNextPage) {
      query.fetchNextPage();
    }
  }, [query.hasNextPage, query.isFetchingNextPage, query.fetchNextPage]);

  // Flatten pages into a single Bead[] for backward compat
  const data = useMemo(
    () => query.data?.pages.flatMap((page) => page.data),
    [query.data],
  );

  return {
    ...query,
    data,
  };
}

export function useBead(beadId: string) {
  return useQuery({
    queryKey: ['bead', beadId],
    queryFn: async () => {
      const response = await api.get<Bead>(`/beads/${beadId}`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!beadId,
  });
}

export function useCreateBead() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      projectId,
      subject,
      description,
      preInstructions,
      beadType,
    }: {
      projectId: string;
      subject: string;
      description: string;
      preInstructions?: string;
      beadType?: string;
    }) => {
      const response = await api.post<Bead>('/beads', {
        projectId,
        subject,
        description,
        preInstructions,
        beadType,
      });
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['beads'] });
      queryClient.setQueryData(['bead', data.id], data);
    },
  });
}

export function useUpdateBead() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      beadId,
      projectId,
      status,
      ...updates
    }: {
      beadId: string;
      projectId: string;
      status?: BeadStatus;
      subject?: string;
      description?: string;
      priority?: number;
      assignedTo?: string | null;
      completionResult?: JobResult;
    }) => {
      const response = await api.patch<Bead>(`/beads/${beadId}`, {
        projectId,
        status,
        ...updates,
      });
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onMutate: async (variables) => {
      const { beadId, projectId, status, ...updates } = variables;
      const patch = { ...updates, ...(status !== undefined ? { status } : {}) };

      // Cancel in-flight fetches so they don't overwrite our optimistic update
      await queryClient.cancelQueries({ queryKey: ['beads', projectId] });
      await queryClient.cancelQueries({ queryKey: ['bead', beadId] });

      // Snapshot previous values for rollback
      const previousBeads = queryClient.getQueriesData({ queryKey: ['beads', projectId] });
      const previousBead = queryClient.getQueryData<Bead>(['bead', beadId]);

      // Optimistically update the infinite query pages
      queryClient.setQueriesData<{ pages: { data: Bead[] }[] }>(
        { queryKey: ['beads', projectId] },
        (old) => {
          if (!old) return old;
          return {
            ...old,
            pages: old.pages.map((page) => ({
              ...page,
              data: page.data.map((b) =>
                b.id === beadId ? { ...b, ...patch } : b
              ),
            })),
          };
        },
      );

      // Optimistically update the single bead query
      if (previousBead) {
        queryClient.setQueryData<Bead>(['bead', beadId], { ...previousBead, ...patch });
      }

      return { previousBeads, previousBead };
    },
    onError: (_err, variables, context) => {
      // Roll back on failure
      if (context?.previousBeads) {
        for (const [queryKey, data] of context.previousBeads) {
          queryClient.setQueryData(queryKey, data);
        }
      }
      if (context?.previousBead) {
        queryClient.setQueryData(['bead', variables.beadId], context.previousBead);
      }
    },
    onSettled: (_data, _err, variables) => {
      // Refetch to ensure server state is in sync
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['bead', variables.beadId] });
    },
  });
}

export function useArchiveBead() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ beadId, projectId }: { beadId: string; projectId: string }) => {
      const response = await api.patch<void>(`/beads/${beadId}/archive?projectId=${projectId}`, {});
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['bead', variables.beadId] });
    },
  });
}

export function useReadyBeads(projectId: string, filters?: {
  status?: string;
  type?: string;
  priority?: string;
  search?: string;
}) {
  const { data: beads } = useBeads(projectId, filters);

  // Filter to beads that have no blockers
  const readyBeads = beads?.filter((bead) => {
    if (bead.status !== 'pending') return false;

    // Check if all blocking beads are completed
    const blockedByCompleted = bead.blockedBy.every((blockerId) => {
      const blocker = beads?.find((b) => b.id === blockerId);
      return blocker?.status === 'completed';
    });

    return blockedByCompleted;
  });

  return readyBeads || [];
}

// Sync all: immediate push + pull (replaces three-way sync)
export interface ThreeWaySyncResult {
  github: {
    pulled: number;
    pushed: number;
    errors: string[];
  };
  local: {
    pulled: number;
    pushed: number;
    errors: string[];
  };
  lastSyncedAt: string;
}

export function useThreeWaySync() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ projectId }: { projectId: string }) => {
      const response = await api.post<ThreeWaySyncResult>(`/sync/${projectId}/sync-all`, {});
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['syncState', variables.projectId] });
    },
  });
}

// Get sync state for a project
export interface SyncState {
  localSyncedAt: string | null;
  githubSyncedAt: string | null;
  localFileHash: string | null;
}

export function useSyncState(projectId: string) {
  return useQuery({
    queryKey: ['syncState', projectId],
    queryFn: async () => {
      const response = await api.get<SyncState>(`/sync/${projectId}/sync-state`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!projectId,
  });
}

// Generate AI suggestions for a project
export function useGenerateSuggestions() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ projectId }: { projectId: string }) => {
      const response = await api.post<{ generated: number; beadIds: string[] }>(
        `/projects/${projectId}/generate-suggestions`,
        {}
      );
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
    },
  });
}

// Accept suggestions (convert to tasks)
export function useAcceptSuggestions() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ projectId, beadIds }: { projectId: string; beadIds?: string[] }) => {
      const response = await api.post<{ accepted: number; total: number }>(
        '/beads/suggestions/accept',
        { projectId, beadIds }
      );
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
    },
  });
}

// Dismiss suggestions (delete)
export function useDismissSuggestions() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ projectId, beadIds }: { projectId: string; beadIds?: string[] }) => {
      const response = await api.post<{ dismissed: number; total: number }>(
        '/beads/suggestions/dismiss',
        { projectId, beadIds }
      );
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
    },
  });
}

// Reconcile beads from all sources (for project import)
export function useReconcileBeads() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ projectId }: { projectId: string }) => {
      const response = await api.post<{
        fromLocal: number;
        fromGitHub: number;
        matched: number;
        errors: string[];
      }>(`/sync/${projectId}/reconcile`, {});
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (data, variables) => {
      queryClient.invalidateQueries({ queryKey: ['beads', variables.projectId] });
      queryClient.invalidateQueries({ queryKey: ['syncState', variables.projectId] });
    },
  });
}

