import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../services/api';
import type { Project, ProjectConfig } from '../types';

export function useProjects() {
  return useQuery({
    queryKey: ['projects'],
    queryFn: async () => {
      const response = await api.get<Project[]>('/projects');
      if (!response.success) {
        throw new Error(response.error);
      }
      // Sort by lastAccessedAt (most recent first), fallback to createdAt for never-accessed projects
      return response.data!.sort((a, b) => {
        const aTime = a.lastAccessedAt ? new Date(a.lastAccessedAt).getTime() : 0;
        const bTime = b.lastAccessedAt ? new Date(b.lastAccessedAt).getTime() : 0;
        return bTime - aTime;
      });
    },
  });
}

export function useProject(id: string) {
  return useQuery({
    queryKey: ['projects', id],
    queryFn: async () => {
      const response = await api.get<Project>(`/projects/${id}`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!id,
  });
}

export function useCreateProject() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (config: Omit<ProjectConfig, 'id'>) => {
      const response = await api.post<Project>('/projects', config);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] });
    },
  });
}

export function useUpdateProject() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, ...data }: Partial<ProjectConfig> & { id: string }) => {
      const response = await api.patch<Project>(`/projects/${id}`, data);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['projects'] });
      queryClient.setQueryData(['projects', data.id], data);
    },
  });
}

export function useDeleteProject() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (id: string) => {
      const response = await api.delete(`/projects/${id}`);
      if (!response.success) {
        throw new Error(response.error);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] });
    },
  });
}

export interface RepoStatus {
  linked: boolean;
  accessible?: boolean;
  reason?: string;
  message: string;
}

export function useRepoStatus(projectId: string, enabled = true) {
  return useQuery({
    queryKey: ['repo-status', projectId],
    queryFn: async () => {
      const response = await api.get<RepoStatus>(`/projects/${projectId}/repo-status`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    enabled: !!projectId && enabled,
    staleTime: 60_000,
  });
}

export function useInitializeProject() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, skipReconcile }: { id: string; skipReconcile?: boolean }) => {
      const params = skipReconcile ? '?skipReconcile=true' : '';
      const response = await api.post<{ status: string }>(`/projects/${id}/initialize${params}`);
      if (!response.success) {
        throw new Error(response.error);
      }
      return response.data!;
    },
    onSuccess: (_data, { id }) => {
      queryClient.invalidateQueries({ queryKey: ['projects', id] });
    },
  });
}

