import { Router } from 'express';
import { v4 as uuidv4 } from 'uuid';
import { beadOps, agentJobOps, projectMemberOps, projectOps, notificationOps, userOps } from '../db/ops.js';
import { pgDb } from '../db/postgres.js';
import { sql, eq } from 'drizzle-orm';
import * as s from '../db/schema.js';
import { requireAuth } from '../middleware/auth.js';
import { requireProjectAccess, requirePermission, getAccessibleProjectIds } from '../middleware/project-access.js';
import { syncOutbox, type SyncEventType } from '../services/sync-outbox.js';
import { githubPuller } from '../services/github-puller.js';
// analyzeTask is no longer called here — analysis runs in E2B sandbox via dispatcher
import { transitionStatus, deleteBead } from '../services/bead-lifecycle.js';
import { utc } from '../utils/timestamps.js';
import { projectEvents } from '../services/project-events.js';
import { logActivity } from '../services/activity-logger.js';
import { createSystemComment } from './bead-comments.js';
import { jobQueue } from '../services/job-queue.js';
import { validate } from '../middleware/validate.js';
import {
  ListBeadsQuery, GetBeadQuery, CreateBeadBody, UpdateBeadBody,
  DeleteBeadQuery, AddDependencyBody, RemoveDependencyQuery,
  HandoffBody, ReportBody, BulkUpdateBody, BulkCloseBody,
  SuggestionActionBody, ProjectIdQuery,
} from '../schemas/index.js';
// scoreSpecificBead moved to sandbox-based analysis runner in agent-dispatch.ts

const router = Router();

// All routes require authentication
router.use(requireAuth);


// Resolve a bead ID that may be a short prefix to a full UUID
async function resolveBeadId(idOrPrefix: string): Promise<string | null> {
  // Already a full UUID
  if (idOrPrefix.length === 36 && idOrPrefix.includes('-')) {
    const existing = await beadOps.findById(idOrPrefix) as any;
    return existing ? idOrPrefix : null;
  }
  // Short prefix — find matching beads
  const matches = await beadOps.findByIdPrefix(idOrPrefix) as any[];
  if (matches.length === 1) return matches[0].id;
  return null; // not found or ambiguous
}

// Resolve assignee to human-readable display info
async function resolveAssigneeDisplay(assignedTo: string | null): Promise<{ assigneeName: string | null; assigneeEmail: string | null }> {
  if (!assignedTo) return { assigneeName: null, assigneeEmail: null };
  if (assignedTo.includes('@')) {
    // Stored as email (pending invitee) — email is the display
    return { assigneeName: null, assigneeEmail: assignedTo };
  }
  // Stored as userId — look up user details
  const user = await userOps.findById(assignedTo) as any;
  if (user) {
    return { assigneeName: user.displayName || null, assigneeEmail: user.email || null };
  }
  return { assigneeName: null, assigneeEmail: null };
}

// Fuzzy assignee resolution: name/username/prefix → userId
// Returns { userId, ambiguous?, candidates? }
async function resolveAssigneeFuzzy(
  input: string,
  projectId: string
): Promise<{ userId: string | null; ambiguous: boolean; candidates?: Array<{ name: string; username: string; email: string }> }> {
  // Build candidate pool: project owner + project members (single JOIN query for members)
  const proj = await projectOps.findById(projectId) as any;
  if (!proj) return { userId: null, ambiguous: false };

  const candidates: Array<{ id: string; name: string; username: string; email: string }> = [];
  const seenIds = new Set<string>();

  // Add owner
  const ownerUser = await userOps.findById(proj.userId) as any;
  if (ownerUser) {
    candidates.push({ id: ownerUser.id, name: ownerUser.displayName || '', username: ownerUser.username || '', email: ownerUser.email || '' });
    seenIds.add(ownerUser.id);
  }

  // Add members with user details in one JOIN query
  const memberRows = await projectMemberOps.findByProjectIdWithUsers(projectId) as any[];
  for (const m of memberRows) {
    if (!seenIds.has(m.userId)) {
      candidates.push({ id: m.userId, name: m.displayName || '', username: m.username || '', email: m.email || '' });
      seenIds.add(m.userId);
    }
  }

  const lower = input.toLowerCase();

  // 1. Exact display_name match
  const exactName = candidates.filter(c => c.name.toLowerCase() === lower);
  if (exactName.length === 1) return { userId: exactName[0].id, ambiguous: false };

  // 2. Exact username match
  const exactUsername = candidates.filter(c => c.username.toLowerCase() === lower);
  if (exactUsername.length === 1) return { userId: exactUsername[0].id, ambiguous: false };

