router.get('/', validate({ query: ListBeadsQuery }), async (req, res) => {
  const { projectId, limit, cursor, status, type, priority, search, parentBeadId } = req.query as unknown as ListBeadsQuery;

  const project = await requireProjectAccess(projectId, req.user!.id);
  if (!project) {
    return res.status(404).json({ error: 'Project not found' });
  }

  try {
    // Pull fresh GitHub state if stale (fire-and-forget on error)
    if (project.githubRepo && project.githubSyncEnabled) {
      try {
        await githubPuller.pullIfStale(project.userId, projectId);
      } catch (err) {
        console.warn('[Beads GET] GitHub pull failed (non-blocking):', err);
      }
    }
    // Fetch one extra to determine hasMore
    const fetchLimit = limit + 1;
    const searchStr = search?.trim() ?? '';

    // Fast path: if search looks like an ID, do indexed lookups first.
    // UUID prefix: hex chars with optional dashes (e.g. "f05aa2c5" or "f05aa2c5-46d6")
    // Local ID: project-name-suffix pattern (e.g. "dev-dash-ukp")
    let idMatches: any[] = [];
    if (searchStr.length >= 3) {
      const isUuidPrefix = /^[0-9a-f][-0-9a-f]*$/i.test(searchStr);
      if (isUuidPrefix) {
        idMatches = await beadOps.findByProjectAndIdPrefix(projectId, searchStr.toLowerCase(), fetchLimit) as any[];
      }
      // Also try local ID prefix match (uses idx_beads_local_bead_id)
      const localIdMatches = await beadOps.findByProjectAndLocalIdPattern(projectId, searchStr, fetchLimit) as any[];
      if (localIdMatches.length > 0) {
        const seen = new Set(idMatches.map((r: any) => r.id));
        for (const row of localIdMatches) {
          if (!seen.has(row.id)) idMatches.push(row);
        }
      }
    }

    // Text search path (subject/description) via existing filtered queries
    // When we have ID matches, pass null for search to get unfiltered results
    // so we can merge; otherwise use the search term for text filtering
    const textSearch = searchStr || null;
    const parentFilter = parentBeadId ?? null;
    let rows: any[];

    if (cursor) {
      const separatorIdx = cursor.indexOf('|');
      if (separatorIdx === -1) {
        return res.status(400).json({ error: 'Invalid cursor format' });
      }
      const cursorDate = cursor.slice(0, separatorIdx);
      const cursorId = cursor.slice(separatorIdx + 1);
      rows = await beadOps.findByProjectIdFilteredAfterCursor(
        projectId,
        (status as string) ?? null,
        (status as string) ?? null,
        (type as string) ?? null,
        (type as string) ?? null,
        priority != null ? Number(priority) : null,
        priority != null ? Number(priority) : null,
        textSearch,
        textSearch,
        textSearch,
        parentFilter,
        parentFilter,
        cursorDate,
        cursorDate,
        cursorId,
        fetchLimit
      ) as any[];
    } else {
      rows = await beadOps.findByProjectIdFiltered(
        projectId,
        (status as string) ?? null,
        (status as string) ?? null,
        (type as string) ?? null,
        (type as string) ?? null,
        priority != null ? Number(priority) : null,
        priority != null ? Number(priority) : null,
        textSearch,
        textSearch,
        textSearch,
        parentFilter,
        parentFilter,
        fetchLimit
      ) as any[];
    }

    // Merge ID matches into text results (ID matches appear first, deduped)
    if (idMatches.length > 0 && !cursor) {
      const textIds = new Set(rows.map((r: any) => r.id));
      const uniqueIdMatches = idMatches.filter((r: any) => !textIds.has(r.id));
      rows = [...uniqueIdMatches, ...rows];
    }

    const hasMore = rows.length > limit;
    if (hasMore) rows = rows.slice(0, limit);

    // Include parent beads so tree view stays intact when search/filter excludes parents
    if (textSearch || status || type || priority) {
      const rowIds = new Set(rows.map((r: any) => r.id));
      const missingParentIds = new Set<string>();
      for (const row of rows) {
        if (row.parentBeadId && !rowIds.has(row.parentBeadId)) {
          missingParentIds.add(row.parentBeadId);
        }
      }
      if (missingParentIds.size > 0) {
        for (const parentId of missingParentIds) {
          const parent = await beadOps.findById(parentId) as any;
          if (parent && parent.projectId === projectId) {
            rows.unshift(parent);
          }
        }
      }
    }

    const beads = await Promise.all(rows.map(formatBeadEnriched));
    const nextCursor = hasMore && rows.length > 0
      ? `${rows[rows.length - 1].createdAt}|${rows[rows.length - 1].id}`
      : null;

    res.json({ data: beads, nextCursor, hasMore });
  } catch (error) {
    console.error('Failed to list beads:', error);
    res.status(500).json({ error: 'Failed to list beads' });
  }
});

export const beadOps = {
  findById: (id: string) =>
    pgDb.select().from(s.beads).where(eq(s.beads.id, id)).then(r => r[0] ?? null),

  findByIdPrefix: (prefix: string) =>
    pgDb.select({ id: s.beads.id }).from(s.beads).where(like(s.beads.id, `${prefix}%`)).limit(2),

  findByProjectId: (projectId: string) =>
    pgDb.select().from(s.beads).where(eq(s.beads.projectId, projectId)).orderBy(desc(s.beads.createdAt)),

  findByProjectIdPaginated: (projectId: string, limit: number) =>
    pgDb.select().from(s.beads).where(eq(s.beads.projectId, projectId))
      .orderBy(desc(s.beads.createdAt), desc(s.beads.id)).limit(limit),

  findByProjectIdAfterCursor: (projectId: string, cursorCreatedAt: string, _cursorCreatedAt2: string, cursorId: string, limit: number) =>
    pgDb.select().from(s.beads)
      .where(and(
        eq(s.beads.projectId, projectId),
        or(
          lt(s.beads.createdAt, new Date(cursorCreatedAt)),
          and(eq(s.beads.createdAt, new Date(cursorCreatedAt)), lt(s.beads.id, cursorId)),
        ),
      ))
      .orderBy(desc(s.beads.createdAt), desc(s.beads.id)).limit(limit),

  findByProjectIdFiltered: (projectId: string, status: string | null, _statusDup: string | null, beadType: string | null, _beadTypeDup: string | null, priority: number | null, _priorityDup: number | null, search: string | null, _searchDup: string | null, _searchDup2: string | null, parentBeadId: string | null, _parentDup: string | null, limit: number) => {
    const conditions = [eq(s.beads.projectId, projectId)];
    if (status) conditions.push(eq(s.beads.status, status));
    if (beadType) conditions.push(eq(s.beads.beadType, beadType));
    if (priority !== null && priority !== undefined) conditions.push(eq(s.beads.priority, priority));
    if (search) conditions.push(or(like(s.beads.subject, `%${search}%`), like(s.beads.description, `%${search}%`))!);
    if (parentBeadId) conditions.push(eq(s.beads.parentBeadId, parentBeadId));
    return pgDb.select().from(s.beads).where(and(...conditions))
      .orderBy(desc(s.beads.createdAt), desc(s.beads.id)).limit(limit);
  },

  findByProjectIdFilteredAfterCursor: (projectId: string, status: string | null, _statusDup: string | null, beadType: string | null, _beadTypeDup: string | null, priority: number | null, _priorityDup: number | null, search: string | null, _searchDup: string | null, _searchDup2: string | null, parentBeadId: string | null, _parentDup: string | null, cursorCreatedAt: string, _cursorCreatedAt2: string, cursorId: string, limit: number) => {
    const conditions = [eq(s.beads.projectId, projectId)];
    if (status) conditions.push(eq(s.beads.status, status));
    if (beadType) conditions.push(eq(s.beads.beadType, beadType));
    if (priority !== null && priority !== undefined) conditions.push(eq(s.beads.priority, priority));
    if (search) conditions.push(or(like(s.beads.subject, `%${search}%`), like(s.beads.description, `%${search}%`))!);
    if (parentBeadId) conditions.push(eq(s.beads.parentBeadId, parentBeadId));
    conditions.push(or(
      lt(s.beads.createdAt, new Date(cursorCreatedAt)),
      and(eq(s.beads.createdAt, new Date(cursorCreatedAt)), lt(s.beads.id, cursorId)),
    )!);
    return pgDb.select().from(s.beads).where(and(...conditions))
      .orderBy(desc(s.beads.createdAt), desc(s.beads.id)).limit(limit);
  },

  findByStatus: (projectId: string, status: string) =>
    pgDb.select().from(s.beads).where(and(eq(s.beads.projectId, projectId), eq(s.beads.status, status))),

  findByGitHubIssue: (projectId: string, githubIssueNumber: number) =>
    pgDb.select().from(s.beads)
      .where(and(eq(s.beads.projectId, projectId), eq(s.beads.githubIssueNumber, githubIssueNumber)))
      .then(r => r[0] ?? null),

  findByLocalBeadId: (localBeadId: string) =>
    pgDb.select().from(s.beads).where(eq(s.beads.localBeadId, localBeadId)).then(r => r[0] ?? null),

  findByProjectAndLocalId: (projectId: string, localBeadId: string) =>
    pgDb.select().from(s.beads)
      .where(and(eq(s.beads.projectId, projectId), eq(s.beads.localBeadId, localBeadId)))
      .then(r => r[0] ?? null),

  findByProjectAndIdPrefix: (projectId: string, prefix: string, limit: number) =>
    pgDb.select().from(s.beads).where(and(eq(s.beads.projectId, projectId), like(s.beads.id, `${prefix}%`))).limit(limit),

  findByProjectAndLocalIdPattern: (projectId: string, prefix: string, limit: number) =>
    pgDb.select().from(s.beads).where(and(eq(s.beads.projectId, projectId), like(s.beads.localBeadId, `${prefix}%`))).limit(limit),

  findChildrenByParent: (parentBeadId: string) =>
    pgDb.select().from(s.beads).where(eq(s.beads.parentBeadId, parentBeadId)),

  create: (id: string, projectId: string, subject: string, description: string | null, status: string, priority: number, owner: string | null, blockedBy: string | null, blocks: string | null, githubIssueNumber: number | null, githubIssueUrl: string | null, localBeadId: string | null, localSyncedAt: string | null, parentBeadId: string | null, beadType: string, preInstructions: string | null) =>
    pgDb.insert(s.beads).values({
      id, projectId, subject, description, status, priority, owner, blockedBy, blocks,
      githubIssueNumber, githubIssueUrl, localBeadId,
      localSyncedAt: localSyncedAt ? new Date(localSyncedAt) : null,
      parentBeadId, beadType, preInstructions,
    }),

  update: (subject: string, description: string | null, status: string, priority: number, owner: string | null, blockedBy: string | null, blocks: string | null, preInstructions: string | null, id: string) =>
    pgDb.update(s.beads).set({ subject, description, status, priority, owner, blockedBy, blocks, preInstructions, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateFull: (subject: string, description: string | null, status: string, priority: number, owner: string | null, blockedBy: string | null, blocks: string | null, preInstructions: string | null, parentBeadId: string | null, beadType: string, assignedTo: string | null, dueDate: string | null, estimatedMinutes: number | null, id: string) =>
    pgDb.update(s.beads).set({
      subject, description, status, priority, owner, blockedBy, blocks, preInstructions,
      parentBeadId, beadType, assignedTo, dueDate, estimatedMinutes, updatedAt: new Date(),
    }).where(eq(s.beads.id, id)),

  updateGitHubIssue: (githubIssueNumber: number | null, githubIssueUrl: string | null, id: string) =>
    pgDb.update(s.beads).set({ githubIssueNumber, githubIssueUrl, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateLocalBead: (localBeadId: string | null, localSyncedAt: string | null, id: string) =>
    pgDb.update(s.beads).set({ localBeadId, localSyncedAt: localSyncedAt ? new Date(localSyncedAt) : null, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateStatus: (status: string, id: string) =>
    pgDb.update(s.beads).set({ status, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateBlockedBy: (blockedBy: string | null, id: string) =>
    pgDb.update(s.beads).set({ blockedBy, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateBlocks: (blocks: string | null, id: string) =>
    pgDb.update(s.beads).set({ blocks, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  clearParentBeadId: (id: string) =>
    pgDb.update(s.beads).set({ parentBeadId: null, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateGitHubIssueId: (githubIssueId: number | null, id: string) =>
    pgDb.update(s.beads).set({ githubIssueId, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateFunctionalArea: (functionalArea: string | null, functionalAreaDesc: string | null, id: string) =>
    pgDb.update(s.beads).set({ functionalArea, functionalAreaDesc, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  findUnclassifiedByProject: (projectId: string) =>
    pgDb.select({ count: count() }).from(s.beads)
      .where(and(eq(s.beads.projectId, projectId), sql`${s.beads.status} != 'completed'`, isNull(s.beads.functionalArea)))
      .then(r => r[0]),

  updateAnalysisResult: (analysisResult: string | null, id: string) =>
    pgDb.update(s.beads).set({ analysisResult, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  updateCompletionResult: (completionResult: string | null, id: string) =>
    pgDb.update(s.beads).set({ completionResult, updatedAt: new Date() }).where(eq(s.beads.id, id)),

  findOrphanedInProgress: () =>
    pgDb.execute(sql`
      SELECT b.* FROM beads b
      WHERE b.status = 'in_progress'
        AND b.id NOT IN (
          SELECT bead_id FROM agent_jobs
          WHERE status IN ('queued', 'running') AND bead_id IS NOT NULL
        )
    `),

  updateBurnScores: (complexityScore: number | null, automabilityScore: number | null, automabilityGrade: string | null, burnScores: string | null, id: string) =>
    pgDb.update(s.beads).set({
      complexityScore, automabilityScore, automabilityGrade, burnScores,
      burnScoredAt: new Date(), updatedAt: new Date(),
    }).where(eq(s.beads.id, id)),

  findUnscoredByProject: (projectId: string) =>
    pgDb.select().from(s.beads).where(and(
