import { useEffect } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { getAuthToken } from '../services/api';

const API_BASE = import.meta.env.VITE_API_URL
  ? `${import.meta.env.VITE_API_URL}/api`
  : '/api';

/**
 * User-level SSE: subscribes to events for ALL projects the authenticated
 * user can access. Mounted at the app level so every page gets real-time
 * updates for cross-cutting concerns (jobStats, notifications, etc.).
 */
export function useUserSSE(userId: string | undefined) {
  const queryClient = useQueryClient();

  useEffect(() => {
    if (!userId) return;

    const token = getAuthToken();
    const params = token ? `?token=${token}` : '';
    const url = `${API_BASE}/events${params}`;
    const source = new EventSource(url, { withCredentials: true });

    source.addEventListener('jobs:changed', (e: MessageEvent) => {
      try {
        const data = JSON.parse(e.data);
        queryClient.invalidateQueries({ queryKey: ['jobs', { projectId: data.projectId }] });
        queryClient.invalidateQueries({ queryKey: ['jobs', data.projectId] });
      } catch {}
      queryClient.invalidateQueries({ queryKey: ['jobs', {}] });
      queryClient.invalidateQueries({ queryKey: ['job'] });
      queryClient.invalidateQueries({ queryKey: ['jobStats'] });
    });

    source.addEventListener('beads:changed', (e: MessageEvent) => {
      try {
        const data = JSON.parse(e.data);
        queryClient.invalidateQueries({ queryKey: ['beads', data.projectId] });
      } catch {}
    });

    source.addEventListener('activity:new', (e: MessageEvent) => {
      try {
        const data = JSON.parse(e.data);
        queryClient.invalidateQueries({ queryKey: ['activity', data.projectId] });
      } catch {}
      queryClient.invalidateQueries({ queryKey: ['activity', 'cross-project'] });
    });

    source.addEventListener('notifications:new', () => {
      queryClient.invalidateQueries({ queryKey: ['notifications'] });
      queryClient.invalidateQueries({ queryKey: ['notifications', 'unread-count'] });
    });

    source.addEventListener('comments:changed', (e: MessageEvent) => {
      try {
        const data = JSON.parse(e.data);
        queryClient.invalidateQueries({ queryKey: ['bead-comments', data.projectId] });
      } catch {}
    });

    source.addEventListener('project:changed', (e: MessageEvent) => {
      try {
        const data = JSON.parse(e.data);
        queryClient.invalidateQueries({ queryKey: ['projects', data.projectId] });
      } catch {}
      queryClient.invalidateQueries({ queryKey: ['projects'] });
    });

    // EventSource auto-reconnects on error
    source.onerror = () => {};

    return () => source.close();
  }, [userId, queryClient]);
}

