/**
 * GET /api/beads/stats — Aggregated bead status counts across all projects
 * the authenticated user has access to. Excludes archived beads.
 * Registered before `/:id` so it isn't swallowed by the param route.
 */
router.get('/stats', async (req, res) => {
  try {
    const userId = req.user!.id;
    const accessibleIds = await getAccessibleProjectIds(userId);

    if (accessibleIds.length === 0) {
      return res.json({ total: 0, pending: 0, in_progress: 0, blocked: 0, completed: 0, failed: 0 });
    }

    const rows = await pgDb
      .select({ status: s.beads.status, count: sql<number>`COUNT(*)::int` })
      .from(s.beads)
      .where(and(
        inArray(s.beads.projectId, accessibleIds),
        sql`${s.beads.status} != 'archived'`,
      ))
      .groupBy(s.beads.status);

    const stats: Record<string, number> = {
      total: 0, pending: 0, in_progress: 0, blocked: 0, completed: 0, failed: 0,
    };
    for (const row of rows) {
      stats[row.status] = Number(row.count);
      stats.total += Number(row.count);
    }
    res.json(stats);
  } catch (error) {
    console.error('Failed to get bead stats:', error);
    res.status(500).json({ error: 'Failed to get bead stats' });
  }
});

