import { Link } from 'react-router-dom';
import { clsx } from 'clsx';
import { useJobStats } from '../../hooks/useJobs';

interface JobExecutionIndicatorProps {
  isCollapsed: boolean;
}

export function JobExecutionIndicator({ isCollapsed }: JobExecutionIndicatorProps) {
  const { data: stats } = useJobStats();

  const running = stats?.concurrency?.running ?? 0;
  const max = stats?.concurrency?.max ?? 3;

  // Slots fill bottom-to-top: index 0 = bottom (lights up first)
  const slots = Array.from({ length: max }, (_, i) => i < running);

  return (
    <Link
      to="/jobs"
      className={clsx(
        'flex border-t border-theme-border group/led transition-colors hover:bg-theme-border/30',
        isCollapsed ? 'flex-col items-center justify-center px-2 py-3' : 'items-center gap-3 px-4 py-3'
      )}
      title={`${running} of ${max} workers active`}
    >
      <div className="flex flex-col-reverse gap-1">
        {slots.map((isActive, i) => (
          <div
            key={i}
            className={clsx(
              'rounded-sm transition-all duration-500',
              isCollapsed ? 'w-6 h-2' : 'w-5 h-2',
              isActive
                ? 'bg-green-400 animate-led-pulse'
                : 'bg-green-900/20 border border-green-800/30'
            )}
          />
        ))}
      </div>
      {!isCollapsed && (
        <span className="text-xs text-theme-muted group-hover/led:text-theme-text transition-colors">
          {running}/{max} active
        </span>
      )}
    </Link>
  );
}

