import React, { useState } from 'react';
import { Outlet } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { Header } from './Header';

interface AppShellProps {
  title?: string;
}

export function AppShell({ title }: AppShellProps) {
  const SIDEBAR_KEY = 'devdash-sidebar-collapsed';
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(() => {
    const stored = localStorage.getItem(SIDEBAR_KEY);
    return stored === null ? true : stored === 'true';
  });

  const toggleSidebar = () => {
    setIsSidebarCollapsed(prev => {
      const next = !prev;
      localStorage.setItem(SIDEBAR_KEY, String(next));
      return next;
    });
  };

  return (
    <div className="min-h-screen bg-theme-bg">
      {/* Sidebar */}
      <Sidebar isCollapsed={isSidebarCollapsed} />

      {/* Main content */}
      <div className={`transition-all duration-300 ${isSidebarCollapsed ? 'pl-16' : 'pl-64'}`}>
        {/* Header */}
        <Header title={title} onToggleSidebar={toggleSidebar} isSidebarCollapsed={isSidebarCollapsed} />

        {/* Page content */}
        <main className="p-6">
          <Outlet />
        </main>
      </div>
    </div>
  );
}

