import React from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { Inspectable } from '../common/Inspectable';
import { clsx } from 'clsx';
import {
  FolderKanban,
  Settings,
  Cpu,
  GitBranch,
  ListTodo,
  Bell,
  Briefcase,
  FlaskConical,
  Target,
  Smartphone,
  Palette,
} from 'lucide-react';
import { JobExecutionIndicator } from './JobExecutionIndicator';
import { useBeadStats } from '../../hooks/useBeads';

interface NavigationItem {
  name: string;
  href: string | ((projectId?: string) => string);
  icon: React.ComponentType<{ className?: string }>;
  indent?: boolean;
  end?: boolean;
}

const navigation: NavigationItem[] = [
  { name: 'Projects', href: '/dashboard', icon: FolderKanban, end: true },
  { name: 'Tasks', href: (projectId?: string) => projectId ? `/project/${projectId}?tab=beads` : '/dashboard', icon: ListTodo, indent: true },
  { name: 'Survey', href: (projectId?: string) => projectId ? `/project/${projectId}?tab=survey` : '/dashboard', icon: Target, indent: true },
  { name: 'Jobs', href: '/jobs', icon: Briefcase },
  { name: 'Notifications', href: '/notifications', icon: Bell },
  { name: 'Settings', href: '/settings', icon: Settings },
  { name: 'Products', href: '/products', icon: Palette },
  { name: 'UI Lab', href: '/lab', icon: FlaskConical },
  { name: 'Mobile', href: '/m', icon: Smartphone },
];

interface SidebarProps {
  isCollapsed: boolean;
}

const LAST_PROJECT_KEY = 'devdash-last-project-id';

// Shared easing/duration so the aside width and the AppShell content offset
// animate in lockstep. Keep in sync with AppShell.tsx.
const TRANSITION = 'transition-[width,padding-left] duration-200 ease-out';

// Labels fade + slide. Delayed on expand so width animates first; instant on
// collapse so labels clear out before the rail narrows.
const labelClass = (isCollapsed: boolean) =>
  clsx(
    'whitespace-nowrap transition-[opacity,transform] duration-150 ease-out',
    isCollapsed
      ? 'opacity-0 -translate-x-1 pointer-events-none'
      : 'opacity-100 translate-x-0 delay-100',
  );

export function Sidebar({ isCollapsed }: SidebarProps) {
  const location = useLocation();
  const { data: beadStats } = useBeadStats();
  const hasInProgress = (beadStats?.in_progress ?? 0) > 0;

  // Extract project ID from URL path directly (useParams doesn't resolve from layout routes)
  const projectMatch = location.pathname.match(/^\/project\/([^/?]+)/);
  const currentProjectId = projectMatch?.[1];

  // Remember the last visited project so Tasks link works from any page
  React.useEffect(() => {
    if (currentProjectId) {
      localStorage.setItem(LAST_PROJECT_KEY, currentProjectId);
    }
  }, [currentProjectId]);

  const resolvedProjectId = currentProjectId || localStorage.getItem(LAST_PROJECT_KEY) || undefined;

  return (
    <Inspectable name="Sidebar">
    <aside
      className={clsx(
        'fixed left-0 top-0 h-screen bg-theme-surface border-r border-theme-border flex flex-col overflow-hidden',
        TRANSITION,
        isCollapsed ? 'w-16' : 'w-52',
      )}
    >
      {/* Logo — icon sits in a fixed w-16 rail so its x position never moves */}
      <div className="h-16 flex items-center border-b border-theme-border flex-shrink-0">
        <div className="w-16 flex items-center justify-center flex-shrink-0">
          <div
            className={clsx(
              'w-8 h-8 bg-brand-primary rounded-lg flex items-center justify-center',
              hasInProgress && 'animate-logo-pulse',
            )}
            title={hasInProgress ? `${beadStats?.in_progress} issue${beadStats?.in_progress === 1 ? '' : 's'} in progress` : undefined}
          >
            <Cpu className="w-5 h-5 text-white" />
          </div>
        </div>
        <span className={clsx('text-lg font-bold text-theme-text', labelClass(isCollapsed))}>
          Dev-Dash
        </span>
      </div>

      {/* Navigation */}
      <nav className="flex-1 py-4 space-y-1">
        {navigation.map((item) => {
          const href = typeof item.href === 'function' ? item.href(resolvedProjectId) : item.href;

          return (
            <NavLink
              key={item.name}
              to={href}
              end={item.end}
              title={isCollapsed ? item.name : ''}
              className={({ isActive }) =>
                clsx(
                  'flex items-center h-10 text-sm font-medium relative group transition-colors',
                  // Indent sub-items only when expanded so the icon rail stays tight when collapsed.
                  item.indent && !isCollapsed && 'pl-4',
                  isActive
                    ? 'bg-brand-primary/10 text-brand-primary'
                    : 'text-theme-muted hover:text-theme-text hover:bg-theme-border/50'
                )
              }
            >
              {/* Icon rail — matches the w-16 collapsed width so icons stay centered at the same x. */}
              <div className="w-16 flex items-center justify-center flex-shrink-0">
                <item.icon className="w-5 h-5" />
              </div>
              <span className={labelClass(isCollapsed)}>{item.name}</span>

              {/* Tooltip for collapsed state */}
              {isCollapsed && (
                <div className="absolute left-full ml-2 px-2 py-1 bg-theme-surface border border-theme-border rounded shadow-lg text-sm whitespace-nowrap opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-50">
                  {item.name}
                </div>
              )}
            </NavLink>
          );
        })}
      </nav>

      {/* Job Execution Indicator */}
      <JobExecutionIndicator isCollapsed={isCollapsed} />

      {/* Footer */}
      <div className="border-t border-theme-border h-12 flex items-center flex-shrink-0">
        <div className="w-16 flex items-center justify-center flex-shrink-0 text-theme-muted">
          <GitBranch className="w-4 h-4" />
        </div>
        <span className={clsx('text-xs text-theme-muted', labelClass(isCollapsed))}>
          Powered by Beads
        </span>
      </div>
    </aside>
    </Inspectable>
  );
}

