import { Link } from 'react-router-dom';
import { clsx } from 'clsx';
import { useJobStats } from '../../hooks/useJobs';

interface JobExecutionIndicatorProps {
  isCollapsed: boolean;
}

export function JobExecutionIndicator({ isCollapsed }: JobExecutionIndicatorProps) {
  const { data: stats } = useJobStats();

  const running = stats?.concurrency?.running ?? 0;
  const max = stats?.concurrency?.max ?? 3;

  // Slots fill bottom-to-top: index 0 = bottom (lights up first)
  const slots = Array.from({ length: max }, (_, i) => i < running);

  return (
    <Link
      to="/jobs"
      className="flex items-center border-t border-theme-border group/led transition-colors hover:bg-theme-border/30 py-3 flex-shrink-0"
      title={`${running} of ${max} workers active`}
    >
      {/* LED stack sits in the same w-16 icon rail used by the rest of the sidebar. */}
      <div className="w-16 flex items-center justify-center flex-shrink-0">
        <div className="flex flex-col-reverse gap-1">
          {slots.map((isActive, i) => (
            <div
              key={i}
              className={clsx(
                'w-5 h-2 rounded-sm transition-all duration-500',
                isActive
                  ? 'bg-green-400 animate-led-pulse'
                  : 'bg-green-900/20 border border-green-800/30'
              )}
            />
          ))}
        </div>
      </div>
      <span
        className={clsx(
          'text-xs text-theme-muted group-hover/led:text-theme-text whitespace-nowrap transition-[opacity,transform,color] duration-150 ease-out',
          isCollapsed
            ? 'opacity-0 -translate-x-1 pointer-events-none'
            : 'opacity-100 translate-x-0 delay-100'
        )}
      >
        {running}/{max} active
      </span>
    </Link>
  );
}

